"use client";

import * as React from "react";
import { Clone, Environment, useGLTF, useTexture } from "@react-three/drei";
import { motion, type MotionValue, useTransform } from "motion/react";
import * as THREE from "three";

import {
  Cinematic3DScene,
  OccludedText,
  type Cinematic3DSceneProps,
  type CinematicCameraBeat,
} from "@/components/experience/cinematic-3d-scene";
import { cn } from "@/lib/utils";

const ASSET_ROOT = "/experience/cinematic-forest-3d";
const FOREST_POSTER = `${ASSET_ROOT}/poster.webp`;
const GROUND_NORMAL_SCALE = new THREE.Vector2(0.88, 0.88);

const DEFAULT_CAMERA: CinematicCameraBeat[] = [
  { at: 0, position: [0, 2.3, 7.2], target: [0, 4.2, -10], fov: 48 },
  { at: 0.22, position: [1.1, 2.45, 2.7], target: [-1.2, 4.45, -13], fov: 46 },
  { at: 0.5, position: [-1.45, 2.58, -3.1], target: [0.4, 4.8, -19], fov: 45 },
  { at: 0.74, position: [2.05, 2.7, -8.7], target: [-0.2, 5.1, -25], fov: 44 },
  { at: 1, position: [-1.7, 2.92, -14.4], target: [1.1, 5.45, -31], fov: 43 },
];

const TREE_GROUPS = [
  { position: [-7.2, 0, -12.5] as [number, number, number], rotation: 0.04, scale: 0.82 },
  { position: [9.5, 0.05, -31] as [number, number, number], rotation: Math.PI + 0.3, scale: 0.94 },
  { position: [-15, 0.08, -48] as [number, number, number], rotation: -0.22, scale: 1.08 },
];

const BROADLEAF_TREES = [
  [-5.8, 0.02, -6.8, 0.38, 2.55],
  [6.8, 0.02, -9.5, -0.42, 2.15],
  [-7.2, 0.04, -17.8, 1.08, 2.7],
  [7.8, 0.05, -22.5, -1.2, 2.45],
  [-6.4, 0.06, -30.5, 0.12, 2.85],
  [6.2, 0.08, -36.8, 1.55, 2.65],
  [-8.4, 0.08, -44.5, -0.74, 3.05],
] as const;

const DISTANT_BROADLEAF_TREES = [
  [-23, -61, 0.2, 3.25], [-11, -68, -0.7, 3.7], [3, -75, 1.1, 3.45], [17, -82, -0.25, 3.9],
  [-17, -94, 0.75, 4.15], [-1, -108, -1.1, 4.4], [18, -121, 0.4, 4.6],
] as const;

const DISTANT_FIR_GROUPS = [
  [-20, -72, 0.22, 1.08],
  [1, -104, Math.PI + 0.16, 1.18],
] as const;

const SAPLING_GROUPS = [
  [-8.2, 0.03, -5.8, 0.15, 3.1],
  [5.8, 0.04, -7.5, -0.4, 2.65],
  [-6.7, 0.05, -20.5, 0.9, 3.4],
  [8.7, 0.07, -23.5, -0.7, 3.75],
  [-9.8, 0.08, -37.5, 0.2, 3.5],
  [6.4, 0.08, -42.5, 1.1, 3.9],
] as const;

const FERN_GROUPS = [
  [-4.6, -2.8, 1.45], [3.6, -3.8, 1.18], [-6.4, -8.7, 1.6], [5.2, -10.4, 1.38],
  [-2.2, -6.2, 1.08], [2.1, -8.1, 1.24], [-4.1, -11.8, 1.3], [3.2, -13.1, 1.16],
  [-3.7, -14.6, 1.34], [7.1, -17.2, 1.75], [-7.8, -22.4, 1.85], [4.4, -25.8, 1.48],
  [-2.8, -19.5, 1.22], [2.7, -23.1, 1.38], [-4.6, -28.2, 1.44], [3.5, -30.4, 1.26],
  [-5.1, -31.5, 1.9], [7.6, -35.7, 1.72], [-8.8, -41.5, 2.05], [5.7, -45.8, 1.68],
  [-2.4, -35.3, 1.34], [2.8, -39.1, 1.46], [-4.2, -43.8, 1.52], [3.6, -47.2, 1.32],
] as const;

const ROCK_GROUPS = [
  [-6.8, -4.1, 0.55, 0.4], [5.8, -12.6, 0.48, -0.6], [-7.5, -27.2, 0.62, 0.8],
  [6.9, -39.2, 0.58, 0.15],
] as const;

export type CinematicForest3DProps = Omit<
  Cinematic3DSceneProps,
  "camera" | "children" | "intro" | "label" | "poster"
> & {
  camera?: CinematicCameraBeat[];
  poster?: string;
  kicker?: string;
  title?: string;
  closingLine?: string;
  assetRoot?: string;
};

function terrainHeightAt(x: number, z: number) {
  return -0.14 + Math.sin(x * 0.115) * Math.cos(z * 0.09) * 0.1;
}

function fadeGroundShader(shader: THREE.WebGLProgramParametersWithUniforms) {
  shader.vertexShader = shader.vertexShader
    .replace("#include <common>", "#include <common>\nvarying float vForestWorldDepth;")
    .replace(
      "#include <begin_vertex>",
      "#include <begin_vertex>\nvForestWorldDepth = -(modelMatrix * vec4(transformed, 1.0)).z;",
    );
  shader.fragmentShader = shader.fragmentShader
    .replace("#include <common>", "#include <common>\nvarying float vForestWorldDepth;")
    .replace(
      "#include <alphatest_fragment>",
      "diffuseColor.a *= 1.0 - smoothstep(48.0, 82.0, vForestWorldDepth);\n#include <alphatest_fragment>",
    );
}

function prepareForestMaterials(...scenes: THREE.Object3D[]) {
  for (const scene of scenes) {
    scene.traverse((object) => {
      if (!(object instanceof THREE.Mesh)) return;
      object.castShadow = false;
      object.receiveShadow = true;
      const materials = Array.isArray(object.material) ? object.material : [object.material];
      for (const material of materials) {
        if (!(material instanceof THREE.MeshStandardMaterial)) continue;
        material.depthWrite = true;
        if (material.transparent || material.alphaMap || material.map?.format === THREE.RGBAFormat) {
          material.transparent = false;
          material.alphaTest = 0.34;
          material.side = THREE.DoubleSide;
        }
        material.needsUpdate = true;
      }
    });
  }
}

function ForestWorld({ assetRoot, quality }: { assetRoot: string; quality: "full" | "balanced" }) {
  const trees = useGLTF(`${assetRoot}/fir-trees.glb`, false, true).scene;
  const broadleafTree = useGLTF(`${assetRoot}/broadleaf-tree.glb`, false, true).scene;
  const saplings = useGLTF(`${assetRoot}/fir-saplings.glb`, false, true).scene;
  const ferns = useGLTF(`${assetRoot}/ferns.glb`, false, true).scene;
  const mossRocks = useGLTF(`${assetRoot}/moss-rocks.glb`, false, true).scene;
  const rootCluster = useGLTF(`${assetRoot}/root-cluster.glb`, false, true).scene;
  const [sourceGroundMap, sourceGroundNormal, sourceGroundRoughness, sourceGroundDisplacement] = useTexture([
    `${assetRoot}/ground-diffuse.jpg`,
    `${assetRoot}/ground-normal.jpg`,
    `${assetRoot}/ground-roughness.jpg`,
    `${assetRoot}/ground-displacement.jpg`,
  ]);
  const [groundMap, groundNormal, groundRoughness, groundDisplacement] = React.useMemo(() => {
    const textures = [
      sourceGroundMap.clone(),
      sourceGroundNormal.clone(),
      sourceGroundRoughness.clone(),
      sourceGroundDisplacement.clone(),
    ] as const;
    for (const texture of textures) {
      texture.wrapS = THREE.RepeatWrapping;
      texture.wrapT = THREE.RepeatWrapping;
      texture.repeat.set(7.5, 10);
      texture.anisotropy = quality === "full" ? 8 : 4;
      texture.needsUpdate = true;
    }
    textures[0].colorSpace = THREE.SRGBColorSpace;
    return textures;
  }, [quality, sourceGroundDisplacement, sourceGroundMap, sourceGroundNormal, sourceGroundRoughness]);
  const terrain = React.useMemo(() => {
    const segments = quality === "full" ? 192 : 96;
    const geometry = new THREE.PlaneGeometry(220, 220, segments, segments);
    geometry.rotateX(-Math.PI / 2);
    geometry.translate(0, 0, -40);
    const position = geometry.getAttribute("position") as THREE.BufferAttribute;
    for (let index = 0; index < position.count; index += 1) {
      const x = position.getX(index);
      const z = position.getZ(index);
      position.setY(index, terrainHeightAt(x, z));
    }
    position.needsUpdate = true;
    geometry.computeVertexNormals();
    return geometry;
  }, [quality]);

  React.useEffect(() => () => terrain.dispose(), [terrain]);

  React.useLayoutEffect(() => {
    prepareForestMaterials(trees, broadleafTree, saplings, ferns, mossRocks, rootCluster);
  }, [broadleafTree, ferns, mossRocks, rootCluster, saplings, trees]);

  React.useEffect(() => () => {
    groundMap.dispose();
    groundNormal.dispose();
    groundRoughness.dispose();
    groundDisplacement.dispose();
  }, [groundDisplacement, groundMap, groundNormal, groundRoughness]);

  const visibleSaplings = quality === "full" ? SAPLING_GROUPS.slice(0, 5) : SAPLING_GROUPS.slice(0, 3);
  const visibleFerns = quality === "full" ? FERN_GROUPS : FERN_GROUPS.slice(0, 8);
  const visibleRocks = quality === "full" ? ROCK_GROUPS : ROCK_GROUPS.slice(0, 3);
  const distantBroadleaf = quality === "full" ? DISTANT_BROADLEAF_TREES.slice(0, 5) : DISTANT_BROADLEAF_TREES.slice(0, 3);
  const distantFirs = DISTANT_FIR_GROUPS.slice(0, 1);

  return (
    <>
      <Environment
        background
        backgroundBlurriness={0}
        backgroundIntensity={0.9}
        environmentIntensity={0.62}
        files={`${assetRoot}/forest-slope-4k.hdr`}
      />
      <hemisphereLight args={["#c8d7bf", "#2b241b", 1.15]} />
      <directionalLight
        castShadow
        color="#fff2cf"
        intensity={2.1}
        position={[-8, 16, 5]}
        shadow-bias={-0.00018}
        shadow-camera-bottom={-20}
        shadow-camera-far={70}
        shadow-camera-left={-24}
        shadow-camera-right={24}
        shadow-camera-top={20}
        shadow-mapSize-height={quality === "full" ? 1024 : 512}
        shadow-mapSize-width={quality === "full" ? 1024 : 512}
      />

      <mesh geometry={terrain} receiveShadow>
        <meshStandardMaterial
          color="#7d8065"
          depthWrite={false}
          displacementMap={groundDisplacement}
          displacementScale={0.34}
          map={groundMap}
          normalMap={groundNormal}
          normalScale={GROUND_NORMAL_SCALE}
          onBeforeCompile={fadeGroundShader}
          roughness={0.98}
          roughnessMap={groundRoughness}
          transparent
        />
      </mesh>

      {TREE_GROUPS.map((tree, index) => (
        <group key={index} position={tree.position} rotation-y={tree.rotation} scale={tree.scale}>
          <Clone object={trees} castShadow={index === 0} receiveShadow />
        </group>
      ))}

      {BROADLEAF_TREES.map(([x, y, z, rotation, scale], index) => (
        <group key={index} position={[x, y, z]} rotation-y={rotation} scale={scale}>
          <Clone object={broadleafTree} castShadow={index < 3} receiveShadow />
        </group>
      ))}

      {distantBroadleaf.map(([x, z, rotation, scale], index) => (
        <group key={index} position={[x, terrainHeightAt(x, z), z]} rotation-y={rotation} scale={scale}>
          <Clone object={broadleafTree} castShadow={false} receiveShadow />
        </group>
      ))}

      {distantFirs.map(([x, z, rotation, scale], index) => (
        <group key={index} position={[x, terrainHeightAt(x, z), z]} rotation-y={rotation} scale={scale}>
          <Clone object={trees} castShadow={false} receiveShadow />
        </group>
      ))}

      {visibleSaplings.map(([x, y, z, rotation, scale], index) => (
        <group key={index} position={[x, y, z]} rotation-y={rotation} scale={scale}>
          <Clone object={saplings} castShadow={false} receiveShadow />
        </group>
      ))}

      {visibleFerns.map(([x, z, scale], index) => (
        <group key={index} position={[x, -0.05, z]} rotation-y={(index * 1.73) % Math.PI} scale={scale}>
          <Clone object={ferns} castShadow={false} receiveShadow />
        </group>
      ))}

      {visibleRocks.map(([x, z, scale, rotation], index) => (
        <group key={index} position={[x, -0.08, z]} rotation-y={rotation} scale={scale}>
          <Clone object={mossRocks} castShadow receiveShadow />
        </group>
      ))}

      <group position={[-4.8, -0.06, -18]} rotation-y={0.32} scale={0.68}>
        <Clone object={rootCluster} castShadow receiveShadow />
      </group>
    </>
  );
}

function ForestNarrative({
  closingLine,
  kicker,
  progress,
  title,
}: {
  closingLine: string;
  kicker: string;
  progress: MotionValue<number>;
  title: string;
}) {
  const openingOpacity = useTransform(progress, [0, 0.08, 0.25, 0.36], [1, 1, 1, 0]);
  const openingY = useTransform(progress, [0, 0.34], [0, -32]);
  const closingOpacity = useTransform(progress, [0.7, 0.82, 0.97], [0, 1, 1]);
  const closingY = useTransform(progress, [0.7, 0.86], [38, 0]);

  return (
    <div className="relative h-full text-white">
      <motion.div
        className="absolute inset-x-[clamp(1.5rem,5vw,5.5rem)] top-[clamp(5.5rem,14vh,9rem)] max-w-[54rem]"
        style={{ opacity: openingOpacity, y: openingY }}
      >
        <p className="text-[0.64rem] font-semibold uppercase tracking-[0.3em] text-white/68">{kicker}</p>
        <h2 className="mt-5 max-w-[10ch] text-[clamp(3.8rem,8.2vw,8.6rem)] font-semibold leading-[0.8] tracking-[-0.075em] text-balance">
          {title}
        </h2>
      </motion.div>

      <motion.div
        className="absolute bottom-[clamp(2.5rem,8vh,6rem)] right-[clamp(1.5rem,6vw,7rem)] max-w-[27rem] text-right"
        style={{ opacity: closingOpacity, y: closingY }}
      >
        <p className="text-[clamp(1.55rem,3vw,3.2rem)] font-medium leading-[0.94] tracking-[-0.045em] text-balance">
          {closingLine}
        </p>
      </motion.div>

      <div className="absolute bottom-6 left-[clamp(1.5rem,5vw,5.5rem)] flex items-center gap-3 text-[0.58rem] font-semibold uppercase tracking-[0.24em] text-white/58">
        <span className="h-px w-9 bg-white/45" />
        Scroll to enter
      </div>
    </div>
  );
}

/**
 * A real 3D forest assembled from scanned/PBR CC0 sources. Studio can replace
 * the world, camera beats and narrative without inheriting this art direction.
 */
export function CinematicForest3D({
  assetRoot = ASSET_ROOT,
  camera = DEFAULT_CAMERA,
  className,
  closingLine = "One world. Real depth. No flat layers.",
  kicker = "Scanned geometry / full vegetation / scroll camera",
  poster = FOREST_POSTER,
  scrollScreens = 6.2,
  title = "Enter a living forest.",
  ...props
}: CinematicForest3DProps) {
  return (
    <Cinematic3DScene
      {...props}
      camera={camera}
      className={cn("[--forest-ink:#f4f1e8]", className)}
      label="Pădure 3D fotorealistă controlată prin scroll"
      poster={poster}
      scrollScreens={scrollScreens}
      intro={(progress) => (
        <ForestNarrative
          closingLine={closingLine}
          kicker={kicker}
          progress={progress}
          title={title}
        />
      )}
      reducedMotionFallback={(
        <section
          aria-label="Pădure 3D fotorealistă"
          className="relative min-h-svh bg-[#07100b] bg-cover bg-center text-white"
          style={{ backgroundImage: `linear-gradient(rgb(3 8 5 / 0.08), rgb(3 8 5 / 0.58)), url(${poster})` }}
        >
          <div className="absolute inset-x-[clamp(1.5rem,5vw,5.5rem)] top-[18vh]">
            <p className="text-[0.64rem] font-semibold uppercase tracking-[0.3em] text-white/68">{kicker}</p>
            <h2 className="mt-5 max-w-[10ch] text-[clamp(3.8rem,8vw,8.4rem)] font-semibold leading-[0.8] tracking-[-0.075em]">{title}</h2>
          </div>
        </section>
      )}
    >
      {({ progress, quality }) => (
        <>
          <ForestWorld assetRoot={assetRoot} quality={quality} />
          <OccludedText
            anchorX="center"
            anchorY="middle"
            beats={[
              { at: 0, opacity: 0, position: [-1.2, 4.4, -17] },
              { at: 0.34, opacity: 0, position: [-3.6, 4.25, -17] },
              { at: 0.5, opacity: 0.86, position: [-2.2, 4.4, -17] },
              { at: 0.7, opacity: 0.86, position: [1.15, 4.55, -17] },
              { at: 0.84, opacity: 0, position: [2.35, 4.65, -17] },
            ]}
            color="#e9eadb"
            fontSize={0.78}
            letterSpacing={-0.045}
            lineHeight={0.88}
            maxWidth={5.6}
            progress={progress}
            textAlign="center"
          >
            THE FOREST OPENS
          </OccludedText>
        </>
      )}
    </Cinematic3DScene>
  );
}

export { DEFAULT_CAMERA as cinematicForestCamera };

"use client";

import * as React from "react";
import { AdaptiveDpr, Clone, Text, useGLTF, useProgress } from "@react-three/drei";
import { Canvas, useFrame, useThree, type ThreeElements } from "@react-three/fiber";
import { type MotionValue, useMotionValue } from "motion/react";
import * as THREE from "three";

import { cn } from "@/lib/utils";
import { IntroLoader } from "@/components/experience/intro-loader";
import {
  damp,
  mix,
  resolveKeyframes,
  sortKeyframes,
  supportsWebGL,
  useHydrated,
  useMediaQuery,
} from "@/components/experience/experience-runtime";
import { useElementScrollProgress } from "@/components/experience/use-element-scroll-progress";

export type CinematicCameraBeat = {
  at: number;
  position: [number, number, number];
  target: [number, number, number];
  fov?: number;
};

export type OccludedTextBeat = {
  at: number;
  opacity: number;
  position?: [number, number, number];
};

export type Cinematic3DSceneRenderProps = {
  progress: MotionValue<number>;
  quality: "full" | "balanced";
};

export type Cinematic3DLoadingControl = {
  active: boolean;
  progress: number;
  label?: string;
  words?: string[];
};

export type Cinematic3DSceneProps = Omit<React.ComponentProps<"section">, "children"> & {
  label: string;
  children: (props: Cinematic3DSceneRenderProps) => React.ReactNode;
  camera: CinematicCameraBeat[];
  poster: string;
  scrollScreens?: number;
  maxDpr?: number;
  smoothing?: number;
  mobileBreakpoint?: number;
  loadingControl?: Cinematic3DLoadingControl;
  intro?: React.ReactNode | ((progress: MotionValue<number>) => React.ReactNode);
  chrome?: React.ReactNode | ((progress: MotionValue<number>) => React.ReactNode);
  reducedMotionFallback?: React.ReactNode;
  onProgressChange?: (progress: number) => void;
};

const DEFAULT_FONT = "/fonts/geist-regular.ttf";

function useNearViewport(target: React.RefObject<HTMLElement | null>) {
  const [near, setNear] = React.useState(true);

  React.useEffect(() => {
    const node = target.current;
    if (!node) return;
    const observer = new IntersectionObserver(
      ([entry]) => setNear(entry?.isIntersecting ?? false),
      { rootMargin: "120% 0px 120% 0px" },
    );
    observer.observe(node);
    return () => observer.disconnect();
  }, [target]);

  return near;
}

function sampleCamera(beats: CinematicCameraBeat[], progress: number) {
  const { from, to, mix: amount } = resolveKeyframes(beats, progress);
  return {
    position: from.position.map((value, index) => mix(value, to.position[index]!, amount)) as [number, number, number],
    target: from.target.map((value, index) => mix(value, to.target[index]!, amount)) as [number, number, number],
    fov: mix(from.fov ?? 44, to.fov ?? 44, amount),
  };
}

/**
 * Reversible scroll camera with frame-rate independent damping. Camera beats
 * are deliberately authored in world units so the scene can enforce a safe
 * minimum distance to hero geometry instead of scaling a raster plate.
 */
export function ScrollCameraRig({
  beats,
  progress,
  smoothing = 7.5,
  onProgressChange,
}: {
  beats: CinematicCameraBeat[];
  progress: MotionValue<number>;
  smoothing?: number;
  onProgressChange?: (progress: number) => void;
}) {
  const sceneCamera = useThree((state) => state.camera) as THREE.PerspectiveCamera;
  const cameraRef = React.useRef(sceneCamera);
  const frames = React.useMemo(() => sortKeyframes(beats), [beats]);
  const smoothed = React.useRef(progress.get());
  const target = React.useMemo(() => new THREE.Vector3(), []);

  React.useEffect(() => {
    cameraRef.current = sceneCamera;
  }, [sceneCamera]);

  useFrame((_, delta) => {
    const camera = cameraRef.current;
    smoothed.current = damp(smoothed.current, progress.get(), smoothing, delta);
    const sampled = sampleCamera(frames, smoothed.current);
    camera.position.set(...sampled.position);
    target.set(...sampled.target);
    camera.lookAt(target);
    if (Math.abs(camera.fov - sampled.fov) > 0.01) {
      camera.fov = sampled.fov;
      camera.updateProjectionMatrix();
    }
    onProgressChange?.(smoothed.current);
  });

  return null;
}

/** Shared GLB instance that is grounded through the same terrain function as the camera scene. */
export function GroundedAsset({
  src,
  x,
  z,
  heightAt,
  groundOffset = 0,
  castShadow = true,
  receiveShadow = true,
  ...props
}: Omit<ThreeElements["group"], "position"> & {
  src: string;
  x: number;
  z: number;
  heightAt: (x: number, z: number) => number;
  groundOffset?: number;
}) {
  const { scene } = useGLTF(src, false, true);
  return (
    <group {...props} position={[x, heightAt(x, z) + groundOffset, z]}>
      <Clone object={scene} castShadow={castShadow} receiveShadow={receiveShadow} />
    </group>
  );
}

function sampleText(beats: OccludedTextBeat[], progress: number) {
  const { from, to, mix: amount } = resolveKeyframes(beats, progress);
  const fromPosition = from.position ?? [0, 0, 0];
  const toPosition = to.position ?? fromPosition;
  return {
    opacity: mix(from.opacity, to.opacity, amount),
    position: fromPosition.map((value, index) => mix(value, toPosition[index]!, amount)) as [number, number, number],
  };
}

/**
 * SDF copy inside the depth buffer. A real mesh can hide it, reveal it and
 * hide it again without DOM z-index tricks. Keep an equivalent semantic copy
 * outside the Canvas for screen readers.
 */
export function OccludedText({
  beats,
  children,
  progress,
  font = DEFAULT_FONT,
  ...props
}: Omit<React.ComponentProps<typeof Text>, "children" | "font" | "position"> & {
  beats: OccludedTextBeat[];
  children: string;
  progress: MotionValue<number>;
  font?: string;
}) {
  const ref = React.useRef<React.ElementRef<typeof Text>>(null);
  const frames = React.useMemo(() => sortKeyframes(beats), [beats]);

  useFrame(() => {
    const text = ref.current;
    if (!text) return;
    const sampled = sampleText(frames, progress.get());
    text.position.set(...sampled.position);
    text.fillOpacity = sampled.opacity;
    text.visible = sampled.opacity > 0.002;
  });

  const first = frames[0]!;
  return (
    <Text
      ref={ref}
      font={font}
      fillOpacity={first.opacity}
      position={first.position ?? [0, 0, 0]}
      {...props}
    >
      {children}
    </Text>
  );
}

function SceneLoadingOverlay({ control }: { control?: Cinematic3DLoadingControl }) {
  const { active, errors, progress, total } = useProgress();
  const started = active || total > 0 || progress > 0 || errors.length > 0;
  const internalLoading = !started || active || (errors.length === 0 && progress < 99.5);
  const loading = control?.active ?? internalLoading;
  const normalizedProgress = control ? control.progress : (started ? progress / 100 : 0);
  return (
    <IntroLoader
      active={loading}
      progress={normalizedProgress}
      storageKey={null}
      minDurationMs={850}
      maxDurationMs={30_000}
      exit="up"
      exitDurationMs={900}
      label={control?.label ?? "Se încarcă scena 3D"}
      words={control?.words ?? ["Capture", "Geometry", "Vegetation", "Atmosphere"]}
      className="bg-[#07100b]"
    >
      <div className="grid place-items-center text-center">
        <div className="grid size-28 place-items-center rounded-full border border-white/15">
          <span className="text-[0.62rem] font-semibold uppercase tracking-[0.28em] text-white/72">Forest<br />01</span>
        </div>
        <p className="mt-5 text-[0.62rem] font-semibold uppercase tracking-[0.24em] text-white/42">Cinematic world loading</p>
      </div>
    </IntroLoader>
  );
}

function renderOverlay(
  overlay: React.ReactNode | ((progress: MotionValue<number>) => React.ReactNode),
  progress: MotionValue<number>,
) {
  return typeof overlay === "function" ? overlay(progress) : overlay;
}

export function Cinematic3DScene({
  camera,
  children,
  chrome,
  className,
  intro,
  label,
  loadingControl,
  maxDpr = 1.5,
  mobileBreakpoint = 900,
  onProgressChange,
  poster,
  reducedMotionFallback,
  scrollScreens = 6.5,
  smoothing = 7.5,
  style,
  ...props
}: Cinematic3DSceneProps) {
  const rootRef = React.useRef<HTMLElement>(null);
  const rawProgress = useElementScrollProgress(rootRef);
  const progress = useMotionValue(0);
  const hydrated = useHydrated();
  const mobile = useMediaQuery(`(max-width: ${mobileBreakpoint - 0.02}px)`);
  const reducedMotion = useMediaQuery("(prefers-reduced-motion: reduce)");
  const constrained = useMediaQuery("(max-resolution: 1.25dppx) and (max-width: 1280px)");
  const nearViewport = useNearViewport(rootRef);
  const [webgl, setWebgl] = React.useState(true);

  React.useEffect(() => {
    const frame = window.requestAnimationFrame(() => setWebgl(supportsWebGL()));
    return () => window.cancelAnimationFrame(frame);
  }, []);

  const fallback = reducedMotionFallback ?? (
    <div className="relative min-h-svh bg-cover bg-center text-white" style={{ backgroundImage: `linear-gradient(rgb(3 7 5 / 0.2), rgb(3 7 5 / 0.72)), url(${poster})` }}>
      {renderOverlay(intro, progress)}
    </div>
  );
  if (hydrated && (mobile || reducedMotion || !webgl)) return <>{fallback}</>;

  return (
    <section
      ref={rootRef}
      aria-label={label}
      className={cn("relative bg-[#07100b]", className)}
      style={{ minHeight: `${scrollScreens * 100}svh`, ...style }}
      {...props}
    >
      <div className="sticky top-0 h-svh overflow-hidden bg-[#07100b]">
        {nearViewport ? (
          <Canvas
            shadows
            dpr={[1, maxDpr]}
            camera={{ fov: camera[0]?.fov ?? 44, near: 0.08, far: 120, position: camera[0]?.position ?? [0, 3, 9] }}
            gl={{ alpha: false, antialias: true, powerPreference: "high-performance" }}
            onCreated={({ gl }) => {
              gl.outputColorSpace = THREE.SRGBColorSpace;
              gl.toneMapping = THREE.ACESFilmicToneMapping;
              gl.toneMappingExposure = 1.02;
              gl.shadowMap.enabled = true;
              gl.shadowMap.type = THREE.PCFSoftShadowMap;
            }}
            performance={{ min: 0.55 }}
          >
            <ScrollCameraRig
              beats={camera}
              progress={rawProgress}
              smoothing={smoothing}
              onProgressChange={(value) => {
                progress.set(value);
                onProgressChange?.(value);
              }}
            />
            {children({ progress, quality: constrained ? "balanced" : "full" })}
            <AdaptiveDpr pixelated={false} />
          </Canvas>
        ) : (
          <div className="absolute inset-0 bg-cover bg-center" style={{ backgroundImage: `url(${poster})` }} aria-hidden="true" />
        )}
        <SceneLoadingOverlay control={loadingControl} />
        <div className="pointer-events-none absolute inset-0 z-10">{renderOverlay(intro, progress)}</div>
        <div className="pointer-events-none absolute inset-0 z-20">{renderOverlay(chrome, progress)}</div>
      </div>
    </section>
  );
}

"use client";

import * as React from "react";

import { cn } from "@/lib/utils";
import { clamp01, damp, usePrefersReducedMotion } from "@/components/experience/experience-runtime";

export type IntroLoaderProps = Omit<React.ComponentProps<"div">, "children"> & {
  /** Accessible name of the loading state. */
  label?: string;
  /** The choreography never finishes before this, even on a warm cache. */
  minDurationMs?: number;
  /** Hard cap: the loader exits at this point even if `load` never fires. */
  maxDurationMs?: number;
  /** Words cycled while loading (brand values, cities, verbs …). */
  words?: string[];
  /**
   * sessionStorage key so the intro plays once per tab session. Pass `null`
   * to play on every mount (e.g. the Lab fixture).
   */
  storageKey?: string | null;
  /**
   * Controlled visibility for loading-screen use (route changes, gallery or
   * scene preloads): the curtain holds while `true` and exits when it flips to
   * `false`. Remount with a new `key` to replay. Leave undefined for the
   * self-timed intro behavior.
   */
  active?: boolean;
  /**
   * Real external progress (0..1), e.g. `loadedAssets / totalAssets`. The
   * counter eases toward it instead of simulating document readiness.
   */
  progress?: number;
  exit?: "up" | "down" | "fade";
  exitDurationMs?: number;
  onComplete?: () => void;
  /** Brand mark / center content. */
  children?: React.ReactNode;
  counterClassName?: string;
  wordClassName?: string;
};

type Phase = "loading" | "exiting" | "done";

const subscribeNoop = () => () => undefined;

/**
 * Hydration-safe "already played" flag: false on the server (the curtain
 * covers first paint), then the real sessionStorage value on the client.
 */
function useSessionFlag(storageKey: string | null) {
  const getSnapshot = React.useCallback(() => {
    if (!storageKey) return false;
    try {
      return sessionStorage.getItem(storageKey) === "1";
    } catch {
      return false;
    }
  }, [storageKey]);
  return React.useSyncExternalStore(subscribeNoop, getSnapshot, () => false);
}

/**
 * Full-page intro choreography: a fixed curtain with a progress counter and a
 * word cycle that tracks real document readiness (eased toward 90%, released
 * to 100% on `load`), then exits with a curtain lift. Plays once per session
 * via `storageKey`, locks scroll only while visible, and is skipped entirely
 * for reduced motion and for visitors who already saw it — the server-rendered
 * curtain is removed before first paint in those cases.
 */
export function IntroLoader({
  active,
  className,
  children,
  counterClassName,
  exit = "up",
  exitDurationMs = 850,
  label = "Loading",
  maxDurationMs = 6000,
  minDurationMs = 1800,
  onComplete,
  progress: externalProgress,
  storageKey = "intro-loader-played",
  wordClassName,
  words,
  ...props
}: IntroLoaderProps) {
  const [phase, setPhase] = React.useState<Phase>("loading");
  const [displayProgress, setDisplayProgress] = React.useState(0);
  const [wordIndex, setWordIndex] = React.useState(0);
  const completedRef = React.useRef(false);
  const controlRef = React.useRef({ active, externalProgress });
  const reducedMotion = usePrefersReducedMotion();
  const played = useSessionFlag(storageKey);
  // Repeat visitors and reduced motion never see the curtain: `played` and the
  // media query both resolve before the post-hydration paint.
  const skip = played || reducedMotion;
  // A controlled `active={false}` starts the exit without waiting for the timeline.
  const exiting = active === false ? phase !== "done" : phase === "exiting";

  React.useEffect(() => {
    controlRef.current = { active, externalProgress };
  }, [active, externalProgress]);

  const complete = React.useCallback(() => {
    if (completedRef.current) return;
    completedRef.current = true;
    if (storageKey) {
      try {
        sessionStorage.setItem(storageKey, "1");
      } catch {
        // Storage can be unavailable (private mode); the intro just replays.
      }
    }
    onComplete?.();
  }, [onComplete, storageKey]);

  React.useEffect(() => {
    if (skip) complete();
  }, [complete, skip]);

  React.useEffect(() => {
    if (phase !== "loading" || skip) return;
    const startedAt = performance.now();
    let previous = startedAt;
    let shown = 0;
    let frame = 0;
    let loaded = document.readyState === "complete";
    const handleLoad = () => {
      loaded = true;
    };
    window.addEventListener("load", handleLoad);
    const tick = (now: number) => {
      const control = controlRef.current;
      if (control.active === false) return;
      const elapsed = now - startedAt;
      // Controlled asset gates must also fail open: a broken CDN response or
      // decoder can never trap the visitor behind a permanent curtain.
      if (control.active !== undefined && elapsed >= maxDurationMs) {
        setPhase("exiting");
        return;
      }
      const delta = Math.min(0.05, Math.max(0.001, (now - previous) / 1000));
      previous = now;
      let next: number;
      if (typeof control.externalProgress === "number") {
        // Controlled mode: the counter eases toward the real reported progress.
        shown = damp(shown, clamp01(control.externalProgress), 7, delta);
        next = shown;
      } else {
        // Ease toward 90% on the minimum timeline; document `load` (or the cap) releases the rest.
        const simulated = 0.9 * (1 - Math.pow(1 - clamp01(elapsed / minDurationMs), 2.2));
        const release = loaded || elapsed >= maxDurationMs ? clamp01((elapsed - minDurationMs) / 400 + simulated) : simulated;
        next = Math.min(1, Math.max(simulated, release));
        shown = next;
      }
      setDisplayProgress(next);
      // A controlled `active` holds the finished curtain until the caller releases it.
      if (next >= 0.995 && elapsed >= minDurationMs && control.active === undefined) {
        setPhase("exiting");
        return;
      }
      frame = requestAnimationFrame(tick);
    };
    frame = requestAnimationFrame(tick);
    return () => {
      cancelAnimationFrame(frame);
      window.removeEventListener("load", handleLoad);
    };
  }, [maxDurationMs, minDurationMs, phase, skip]);

  React.useEffect(() => {
    if (phase !== "loading" || exiting || skip || !words || words.length < 2) return;
    const interval = setInterval(() => setWordIndex((index) => (index + 1) % words.length), 420);
    return () => clearInterval(interval);
  }, [exiting, phase, skip, words]);

  // Scroll stays locked only while the curtain is actually covering content.
  React.useEffect(() => {
    if (phase !== "loading" || exiting || skip) return;
    const previous = document.documentElement.style.overflow;
    document.documentElement.style.overflow = "hidden";
    return () => {
      document.documentElement.style.overflow = previous;
    };
  }, [exiting, phase, skip]);

  React.useEffect(() => {
    if (!exiting || skip) return;
    const timeout = setTimeout(() => {
      setPhase("done");
      complete();
    }, exitDurationMs);
    return () => clearTimeout(timeout);
  }, [complete, exitDurationMs, exiting, skip]);

  if (skip || phase === "done") return null;

  const exitTransform = exit === "up" ? "translateY(-100%)" : exit === "down" ? "translateY(100%)" : "none";

  return (
    <div
      role="status"
      aria-label={label}
      data-intro-loader
      data-phase={phase}
      className={cn("fixed inset-0 z-[90] flex flex-col justify-between overflow-hidden bg-[#0a0a0a] text-white", className)}
      style={{
        transform: exiting ? exitTransform : "none",
        opacity: exiting && exit === "fade" ? 0 : 1,
        transition: exiting ? `transform ${exitDurationMs}ms cubic-bezier(.76,0,.24,1), opacity ${exitDurationMs}ms ease` : undefined,
        pointerEvents: exiting ? "none" : undefined,
      }}
      {...props}
    >
      <div className="flex flex-1 items-center justify-center">{children}</div>
      <div className="flex items-end justify-between p-6 sm:p-10">
        {words && words.length > 0 ? (
          <span aria-hidden className={cn("text-xs font-semibold uppercase tracking-[0.22em] opacity-60", wordClassName)}>
            {words[wordIndex]}
          </span>
        ) : (
          <span />
        )}
        <span aria-hidden className={cn("font-mono text-5xl font-semibold tabular-nums tracking-tight sm:text-7xl", counterClassName)}>
          {String(Math.round(displayProgress * 100)).padStart(3, "0")}
        </span>
      </div>
    </div>
  );
}

"use client";

import * as React from "react";

const subscribeToHydration = () => () => undefined;

export function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

export function useMediaQuery(query: string, serverValue = false) {
  const subscribe = React.useCallback(
    (onChange: () => void) => {
      const media = window.matchMedia(query);
      media.addEventListener("change", onChange);
      return () => media.removeEventListener("change", onChange);
    },
    [query],
  );
  const getSnapshot = React.useCallback(() => window.matchMedia(query).matches, [query]);
  return React.useSyncExternalStore(subscribe, getSnapshot, () => serverValue);
}

/**
 * Hydration-safe reduced-motion preference: false on the server and during
 * hydration, then live. Replaces the repeated `mounted && useReducedMotion()`
 * pattern.
 */
export function usePrefersReducedMotion() {
  return useMediaQuery("(prefers-reduced-motion: reduce)");
}

/** True on touch-first devices; use to swap pointer effects for static or rail modes. */
export function useCoarsePointer() {
  return useMediaQuery("(pointer: coarse)");
}

/** True only when a hover-capable precise pointer is present. */
export function useFinePointer() {
  return useMediaQuery("(hover: hover) and (pointer: fine)");
}

export function clamp01(value: number) {
  return Math.min(1, Math.max(0, value));
}

export function mix(from: number, to: number, amount: number) {
  return from + (to - from) * amount;
}

export function damp(current: number, target: number, smoothing: number, deltaSeconds: number) {
  return mix(current, target, 1 - Math.exp(-Math.max(0.01, smoothing) * deltaSeconds));
}

/** Returns the frames sorted by `at`, reusing the input when it is already ordered. */
export function sortKeyframes<T extends { at: number }>(frames: T[]): T[] {
  for (let index = 1; index < frames.length; index += 1) {
    if (frames[index - 1]!.at > frames[index]!.at) {
      return [...frames].sort((left, right) => left.at - right.at);
    }
  }
  return frames;
}

export function resolveKeyframes<T extends { at: number }>(
  frames: T[],
  progress: number,
): { from: T; to: T; mix: number } {
  if (frames.length === 0) throw new Error("Experience keyframes cannot be empty.");
  const sorted = sortKeyframes(frames);
  if (progress <= sorted[0]!.at) return { from: sorted[0]!, to: sorted[0]!, mix: 0 };
  for (let index = 0; index < sorted.length - 1; index += 1) {
    const from = sorted[index]!;
    const to = sorted[index + 1]!;
    if (progress <= to.at) {
      const span = Math.max(0.0001, to.at - from.at);
      return { from, to, mix: clamp01((progress - from.at) / span) };
    }
  }
  const final = sorted.at(-1)!;
  return { from: final, to: final, mix: 0 };
}

export function supportsWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(
      canvas.getContext("webgl2", { failIfMajorPerformanceCaveat: true })
      || canvas.getContext("webgl", { failIfMajorPerformanceCaveat: true }),
    );
  } catch {
    return false;
  }
}

