  }, null, 2)}\n`,
);

const total = (await Promise.all(outputs.map((file) => stat(path.join(OUTPUT_DIR, file)))))
  .reduce((sum, file) => sum + file.size, 0);
console.log(`Built ${(total / 1024 / 1024).toFixed(1)} MiB of production forest assets.`);
